import React, { useCallback, useEffect, useMemo, useState } from "react"
import { Link } from "gatsby"
import { useParams } from "@gatsbyjs/reach-router"
import { Layout } from "../../components/Layout"
import { Seo } from "../../components/Seo"
import { DynamicForm } from "../../components/DynamicForm"
import { FormPreview } from "../../components/FormPreview"
import { apiJson } from "../../utils/api"
import { buildDefaultValues } from "../../utils/fieldKey"

function storageKey(formId) {
  return `crm_submission_${formId}`
}

export default function UserFormPage({ params: paramsProp }) {
  const reach = useParams()
  const slug = paramsProp?.slug ?? reach?.slug
  const [form, setForm] = useState(null)
  const [values, setValues] = useState({})
  const [submissionId, setSubmissionId] = useState(null)
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [message, setMessage] = useState(null)
  const [error, setError] = useState(null)

  useEffect(() => {
    let cancelled = false
    async function load() {
      setLoading(true)
      setError(null)
      try {
        const f = await apiJson(`/api/forms/by-slug/${encodeURIComponent(slug)}`)
        if (cancelled) return
        setForm(f)
        const defaults = buildDefaultValues(f.schema)
        let sid =
          typeof window !== `undefined` ? window.localStorage.getItem(storageKey(f.id)) : null
        if (sid) {
          try {
            const sub = await apiJson(`/api/submissions/${encodeURIComponent(sid)}`)
            if (sub && sub.formId === f.id) {
              setSubmissionId(sub.id)
              setValues({ ...defaults, ...sub.data })
              setLoading(false)
              return
            }
          } catch {
            sid = null
          }
        }
        setValues(defaults)
        setSubmissionId(null)
      } catch (e) {
        if (!cancelled) setError(e.message || `Failed to load form`)
      } finally {
        if (!cancelled) setLoading(false)
      }
    }
    if (slug) load()
    return () => {
      cancelled = true
    }
  }, [slug])

  const onSave = useCallback(async () => {
    if (!form) return
    setSaving(true)
    setMessage(null)
    setError(null)
    try {
      if (submissionId) {
        const sub = await apiJson(`/api/submissions/${encodeURIComponent(submissionId)}`, {
          method: `PUT`,
          body: JSON.stringify({ data: values }),
        })
        setMessage(`Saved.`)
        setValues({ ...values, ...sub.data })
      } else {
        const sub = await apiJson(`/api/forms/${encodeURIComponent(form.id)}/submissions`, {
          method: `POST`,
          body: JSON.stringify({ data: values }),
        })
        setSubmissionId(sub.id)
        if (typeof window !== `undefined`) {
          window.localStorage.setItem(storageKey(form.id), sub.id)
        }
        setMessage(`Saved. Your edits are linked on this browser.`)
      }
    } catch (e) {
      setError(e.message || `Save failed`)
    } finally {
      setSaving(false)
    }
  }, [form, submissionId, values])

  const title = useMemo(() => form?.title || `Form`, [form])

  if (!slug) {
    return (
      <Layout title="Form">
        <p className="error">Missing form slug.</p>
      </Layout>
    )
  }

  return (
    <Layout title={loading ? `Loading…` : title}>
      <Seo title={title} description={form?.description} />
      <p className="muted">
        <Link to="/">Home</Link>
        {form ? (
          <>
            {" "}
            · <span className="badge">{form.slug}</span>
          </>
        ) : null}
      </p>

      {error ? <p className="error">{error}</p> : null}
      {message ? <p className="success">{message}</p> : null}

      {loading ? <p className="muted">Loading form…</p> : null}

      {!loading && form ? (
        <div className="grid-two" style={{ marginTop: 16 }}>
          <div className="panel">
            <h2 style={{ marginTop: 0, fontSize: "1.15rem" }}>Edit</h2>
            {form.description ? <p className="muted">{form.description}</p> : null}
            <DynamicForm
              schema={form.schema}
              values={values}
              onChange={setValues}
              onSubmit={onSave}
              submitLabel={saving ? `Saving…` : `Save`}
              disabled={saving}
            />
          </div>
          <FormPreview schema={form.schema} values={values} />
        </div>
      ) : null}
    </Layout>
  )
}
